INSERT INTO public.doctors (department_id, name, slug, qualification, experience_years, designation, bio, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Dr. Ramesh Agarwal', 'dr-ramesh-agarwal', 'MS (Orthopaedics) — Gold Medalist, MBBS — Rajasthan University, Fellowship in Joint Replacement Surgery, Member, Indian Orthopaedic Association (IOA)', 25, 'Sr. Consultant Orthopedic & Joint Replacement Surgeon', 'Dr. Ramesh Agarwal is the founder and senior consultant at Balaji Hospital & Orthopaedic Centre, Jaipur. With over 25 years of hands-on expertise, he specialises in complex spine surgeries, total knee and hip replacement, and trauma management. He founded the hospital in 1996 with the vision of making world-class orthopaedic care accessible to all sections of society. His patient-first approach and precise surgical skills have earned him the trust of thousands of patients across Rajasthan.', '/images/doctors/ramesh-agarwal.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.doctors (department_id, name, slug, qualification, experience_years, designation, bio, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Dr. Shitiz Agarwal', 'dr-shitiz-agarwal', 'MS (Orthopaedics), MBBS, Fellowship in Arthroscopy & Sports Medicine, Member, Indian Orthopaedic Association (IOA)', 12, 'Consultant Orthopedic Surgeon', 'Dr. Shitiz Agarwal is a skilled orthopaedic surgeon specialising in trauma, sports injuries, and arthroscopic procedures. He brings a modern approach to treatment, incorporating minimally invasive surgical techniques that accelerate recovery and reduce post-operative pain. He is deeply committed to evidence-based medicine and continuous learning, regularly participating in national orthopaedic conferences and workshops.', '/images/doctors/ramesh-agarwal-alt.jpg', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.doctors (department_id, name, slug, qualification, experience_years, designation, bio, image_url, is_active) VALUES ('d4000000-0000-0000-0000-000000000000', 'Dr. Alok Maheshwari', 'dr-alok-maheshwari', 'MS (ENT & Head-Neck Surgery), MBBS, Fellowship in Endoscopic Sinus Surgery, Training in Plastic & Reconstructive Surgery, Life Member, Association of Otolaryngologists of India (AOI)', 18, 'Consultant — ENT, Plastic & Vascular Surgery', 'Dr. Alok Maheshwari is a highly experienced ENT and plastic/vascular surgeon. He has performed thousands of microsurgical ear procedures, functional endoscopic sinus surgeries (FESS), and complex vascular reconstructions. His dual expertise in ENT and plastic surgery allows him to offer comprehensive head and neck surgical care with exceptional aesthetic and functional outcomes.', '/images/gallery/ot.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.doctors (department_id, name, slug, qualification, experience_years, designation, bio, image_url, is_active) VALUES ('d5000000-0000-0000-0000-000000000000', 'Dr. Sheela Agarwal', 'dr-sheela-agarwal', 'BPT (Bachelor of Physiotherapy) — Rajasthan University, MPT (Master of Physiotherapy) — Specialisation in Musculoskeletal, Certified in Sports Rehabilitation, Member, Indian Association of Physiotherapists (IAP)', 20, 'Physiotherapy & Rehabilitation Specialist', 'Dr. Sheela Agarwal heads the Physiotherapy & Rehabilitation department at Balaji Hospital. With over 20 years of experience, she has developed and led rehabilitation programs for post-surgical orthopaedic patients, accident victims, and patients with neurological conditions. Her holistic approach combines manual therapy, exercise-based rehabilitation, and patient education to achieve maximum functional recovery in the shortest time.', '/images/gallery/physiotherapy.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Spine Treatment', 'spine-treatment', 'Comprehensive care for spinal disorders including herniated discs, spinal stenosis, scoliosis, and complex deformity correction. We offer both surgical and non-surgical approaches.', 'Activity', '/images/services/spine.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Knee Replacement', 'knee-replacement', 'Advanced total and partial knee replacement surgery using minimally invasive techniques for faster recovery, reduced pain, and improved mobility in arthritis patients.', 'Stethoscope', '/images/services/knee.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Hip Replacement', 'hip-replacement', 'Expert surgical solutions for chronic hip pain, avascular necrosis, and arthritis — restoring an active, pain-free lifestyle using cemented and cementless prostheses.', 'HeartPulse', '/images/services/hip.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Fracture Treatment', 'fracture-treatment', 'Emergency and specialized care for all types of bone fractures — from simple closed fractures to complex open fractures — using modern internal and external fixation methods.', 'Bone', '/images/services/fracture.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Shoulder Arthroscopy', 'shoulder-arthroscopy', 'Minimally invasive arthroscopic surgery for shoulder injuries including rotator cuff tears, shoulder instability, SLAP lesions, and frozen shoulder (adhesive capsulitis).', 'Activity', '/images/services/shoulder.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Ankle Replacement', 'ankle-replacement', 'Modern total ankle arthroplasty for end-stage arthritis of the ankle joint, offering better motion preservation and faster recovery compared to traditional fusion surgery.', 'Activity', '/images/services/ankle.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Hand & Upper Limb Surgery', 'hand-upper-limb', 'Specialized surgical treatment for hand and wrist conditions: carpal tunnel syndrome, trigger finger, tendon injuries, nerve repair, and congenital deformities.', 'Stethoscope', '/images/services/hand.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Joint Pain Treatment', 'joint-pain-treatment', 'Comprehensive management of acute and chronic joint pain through physiotherapy, intra-articular injections, PRP therapy, and surgical intervention when necessary.', 'HeartPulse', '/images/services/joint-pain.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Sports Medicine', 'sports-medicine', 'Dedicated sports injury management including ACL/PCL reconstruction, meniscus repair, and rehabilitation programs designed to get athletes back to peak performance.', 'Activity', '/images/services/sports.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Paediatric Orthopaedics', 'paediatric-orthopaedics', 'Specialized orthopaedic care for children — treating clubfoot, bone infections, developmental hip dysplasia, limb deformities, and paediatric fractures with child-friendly approaches.', 'Users', '/images/services/paediatric.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d1000000-0000-0000-0000-000000000000', 'Physiotherapy & Rehabilitation', 'physiotherapy', 'Fully equipped physiotherapy centre offering post-operative rehabilitation, sports injury recovery, chronic pain management, and neurological rehabilitation programs.', 'HeartPulse', '/images/services/physiotherapy.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d2000000-0000-0000-0000-000000000000', 'Ear Surgery', 'ear-surgery', 'Microscopic and endoscopic ear surgeries for hearing restoration, chronic suppurative otitis media (CSOM), tympanoplasty, mastoidectomy, and stapedectomy.', 'Microscope', '/images/services/ear.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d2000000-0000-0000-0000-000000000000', 'Nose Surgery', 'nose-surgery', 'Functional and cosmetic nasal surgeries including septoplasty, FESS (endoscopic sinus surgery), rhinoplasty, and treatment of nasal polyps and chronic sinusitis.', 'Wind', '/images/services/nose.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d2000000-0000-0000-0000-000000000000', 'Throat Surgery', 'throat-surgery', 'Specialized care for voice disorders, recurrent tonsillitis (tonsillectomy/adenoidectomy), laryngeal conditions, dysphagia, and sleep apnea-related surgeries.', 'Wind', '/images/services/throat.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d3000000-0000-0000-0000-000000000000', 'Plastic & Vascular Surgery', 'plastic-vascular-surgery', 'Comprehensive plastic and vascular surgery services: wound reconstruction, skin grafts, varicose vein treatment, and vascular bypass procedures for optimal outcomes.', 'HeartPulse', '/images/services/plastic.png', true) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (department_id, title, slug, description, icon, image_url, is_active) VALUES ('d3000000-0000-0000-0000-000000000000', 'Kidney Stones Treatment', 'kidney-stones', 'Modern laser lithotripsy and non-invasive ESWL for effective removal of kidney and urinary stones with minimal recovery time and maximum precision.', 'Flame', '/images/services/kidney.png', true) ON CONFLICT (id) DO NOTHING;
